const items = $input.all();
const results = [];

for (const item of items) {
  try {
    // Handle both Gemini and Claude response structures
    let rawText;

    if (item.json.content?.parts) {
      // Gemini structure
      rawText = item.json.content.parts[0].text;
    } else if (Array.isArray(item.json.content)) {
      // Claude structure
      rawText = item.json.content[0].text;
    } else {
      throw new Error("Unknown response structure");
    }

    // Remove markdown code fences if present
    rawText = rawText.replace(/```json/g, '').replace(/```/g, '').trim();

    const parsed = JSON.parse(rawText);
    results.push({ json: parsed });
  } catch (error) {
    results.push({ 
      json: { 
        error: "Parse failed", 
        error_message: error.message,
        raw_text: JSON.stringify(item.json)
      } 
    });
  }
}

return results;

const items = $input.all();
const results = [];

function toBulletList(arr) {
  if (!Array.isArray(arr)) return arr || '';
  return '<ul style="margin:5px 0; padding-left:20px;">' + 
    arr.map(item => `<li style="margin-bottom:5px; color:#555;">${item}</li>`).join('') + 
    '</ul>';
}

for (const item of items) {
  const data = item.json;

  results.push({
    json: {
      ...data,
      features_html: toBulletList(data.features),
      pros_html: toBulletList(data.pros),
      cons_html: toBulletList(data.cons),
      alternatives_html: toBulletList(data.alternatives),
      learning_roadmap_html: toBulletList(data.learning_roadmap),
      portfolio_project_ideas_html: toBulletList(data.portfolio_project_ideas),
      tools_needed_html: Array.isArray(data.weekly_challenge_project?.tools_needed) 
        ? data.weekly_challenge_project.tools_needed.join(', ') 
        : ''
    }
  });
}

return results;
